import{_ as l,c as i,o as e,a}from"./app.87b1f767.js";const S=JSON.parse('{"title":"数据库介绍","description":"","frontmatter":{},"headers":[{"level":2,"title":"数据库概念","slug":"数据库概念","link":"#数据库概念","children":[]},{"level":2,"title":"关系型数据库与非关系型数据库","slug":"关系型数据库与非关系型数据库","link":"#关系型数据库与非关系型数据库","children":[]},{"level":2,"title":"常见的数据库产品","slug":"常见的数据库产品","link":"#常见的数据库产品","children":[{"level":3,"title":"关系型数据库","slug":"关系型数据库","link":"#关系型数据库","children":[]},{"level":3,"title":"非关系型数据库","slug":"非关系型数据库","link":"#非关系型数据库","children":[]}]},{"level":2,"title":"数据库术语","slug":"数据库术语","link":"#数据库术语","children":[]},{"level":2,"title":"MySQL 管理工具","slug":"mysql-管理工具","link":"#mysql-管理工具","children":[]}],"relativePath":"mysql/introduce.md"}'),d={name:"mysql/introduce.md"},r=a('<h1 id="数据库介绍" tabindex="-1">数据库介绍 <a class="header-anchor" href="#数据库介绍" aria-hidden="true">#</a></h1><h2 id="数据库概念" tabindex="-1">数据库概念 <a class="header-anchor" href="#数据库概念" aria-hidden="true">#</a></h2><ul><li><p>数据库就是存放数据的仓库</p></li><li><p>数据库（DataBase 简称 DB）是长期存储在计算机内部有结构的、大量的、共享的数据集合</p></li><li><p>长期存储：持久存储</p></li><li><p>有结构：</p><ul><li>类型：数据库不仅可以存放数据、而且存放的数据还是有类型的</li><li>关系：存储数据与数据直接的关系</li></ul></li><li><p>大量：大多数数据库都是文件系统的，也就是说存储在数据库中的数据实际上就是存储在硬盘当中</p></li><li><p>共享：多个应用程序可以通过数据库实现数据共享</p></li></ul><h2 id="关系型数据库与非关系型数据库" tabindex="-1">关系型数据库与非关系型数据库 <a class="header-anchor" href="#关系型数据库与非关系型数据库" aria-hidden="true">#</a></h2><ul><li><p>关系型数据库</p><ul><li>采用关系模型，来组织数据的存储，以行和列的形式存储数据并记录数据与数据直接的关系</li><li>将数据存储在表格中，可以通过表格与表格之间的关联来维护数据与数据之间的关系</li></ul></li><li><p>非关系型数据库</p><ul><li>采用键值对的模型来存储数据，只完成数据的记录，不会记录数据与数据直接的关系</li><li>在非关系型数据库中基于特定的存储结构来解决一些大数据应用的难题</li><li>NoSQL 来指代非关系型数据库</li></ul></li></ul><h2 id="常见的数据库产品" tabindex="-1">常见的数据库产品 <a class="header-anchor" href="#常见的数据库产品" aria-hidden="true">#</a></h2><h3 id="关系型数据库" tabindex="-1">关系型数据库 <a class="header-anchor" href="#关系型数据库" aria-hidden="true">#</a></h3><ul><li><code>MySql</code> 免费 <ul><li>MariaDB</li><li>Percona Server</li></ul></li><li>PostgreSQL</li><li><code>Oracle</code> 收费</li><li>SQL Server</li><li>Access</li><li>Sybase</li><li>达梦数据库（国产）</li></ul><h3 id="非关系型数据库" tabindex="-1">非关系型数据库 <a class="header-anchor" href="#非关系型数据库" aria-hidden="true">#</a></h3><ul><li>面向检索的列式存储 Colimn-Oriented <ul><li>HaBase（Hadoop子系统）</li><li>BigTable（Google）</li></ul></li><li>面向高并发的缓存存储 Key-Value <ul><li><code>Redis</code></li><li>MemcacheDB</li></ul></li><li>面向海量数据访问的文档存储 Document-Oriented <ul><li><code>MongoDB</code></li><li>CouchDB</li></ul></li></ul><h2 id="数据库术语" tabindex="-1">数据库术语 <a class="header-anchor" href="#数据库术语" aria-hidden="true">#</a></h2><ul><li><code>数据库（Database）</code>：存储数据的集合</li><li><code>数据（Data）</code>：实际上指的是描述事务的符合记录</li><li><code>数据库管理系统（Database Management System，简称 DBMS）</code>：是位于用户与操作系统之间的一层数据管理软件</li><li><code>数据库管理员（Database Administrator，简称 DBA）</code>：负责数据库创建、使用、维护的专门人员</li><li><code>数据库系统（Database System，简称 DBS）</code>：数据库系统管理员、数据库管理系统及数据库系统组成的整个单元</li></ul><h2 id="mysql-管理工具" tabindex="-1">MySQL 管理工具 <a class="header-anchor" href="#mysql-管理工具" aria-hidden="true">#</a></h2><ul><li>当完成数据库安装之后，MySQL 是以服务的形式运行在 windows/linux 系统，用户是通过 DBMS 工具对 MySQL 进行操作的，当我们安装完成 MySQL 之后默认安装了 <code>MySQL Commcand Line Client</code> 此工具是一个命令行形式的工具，通常我们会单独安装可视化的 DBMS 工具 <ul><li>SQLyog</li><li>Navicat</li></ul></li></ul>',14),t=[r];function c(n,o,s,h,u,p){return e(),i("div",null,t)}const m=l(d,[["render",c]]);export{S as __pageData,m as default};
